import{c as e,Q as a,j as r,m as n}from"./chunks/framework.BPKcPtvA.js";const u=JSON.parse('{"title":"Migrations","description":"","frontmatter":{},"headers":[],"relativePath":"guide/admin/migrations.md","filePath":"guide/admin/migrations.md","lastUpdated":1778862269000}'),o={name:"guide/admin/migrations.md"};function s(i,t,l,d,c,g){return a(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="migrations" tabindex="-1">Migrations <a class="header-anchor" href="#migrations" aria-label="Permalink to &quot;Migrations&quot;">​</a></h1><p>The <strong>Migrations</strong> page is where you launch and track tenant-level operations that touch the underlying instances — cloning, deleting, exporting, importing, and replacing entire instances.</p><h2 id="what-you-can-do" tabindex="-1">What you can do <a class="header-anchor" href="#what-you-can-do" aria-label="Permalink to &quot;What you can do&quot;">​</a></h2><p>Five job types:</p><table tabindex="0"><thead><tr><th>Job type</th><th>What it does</th></tr></thead><tbody><tr><td><strong>Tenant Clone</strong></td><td>Duplicates a tenant onto a target instance, with optional user-email remapping.</td></tr><tr><td><strong>Tenant Delete</strong></td><td>Removes a tenant from its instance and from the Console. Destructive.</td></tr><tr><td><strong>Tenant Export</strong></td><td>Packages a tenant&#39;s data into a downloadable artifact.</td></tr><tr><td><strong>Tenant Import</strong></td><td>Restores a tenant from a previously exported artifact, on a target instance.</td></tr><tr><td><strong>Instance Replace</strong></td><td>Moves every tenant from one instance to another in bulk. Each tenant becomes a sub-job; the parent tracks overall progress.</td></tr></tbody></table><p>Every job can be run as a <strong>dry run</strong> first. Dry runs walk through the whole flow without writing destructive changes — they are the recommended way to validate a job before letting it act for real.</p><h2 id="list-page" tabindex="-1">List page <a class="header-anchor" href="#list-page" aria-label="Permalink to &quot;List page&quot;">​</a></h2><h3 id="toolbar" tabindex="-1">Toolbar <a class="header-anchor" href="#toolbar" aria-label="Permalink to &quot;Toolbar&quot;">​</a></h3><ul><li><strong>Search</strong> — free-text across job number, ID, tenant name, error message, actor email.</li><li><strong>Type</strong> — Tenant Clone / Delete / Export / Import / Instance Replace.</li><li><strong>Instance</strong> — filter by source or target instance.</li><li><strong>Status</strong> — All / Active / Succeeded / Failed.</li><li><strong>Time Range</strong> — 7 days / 30 days / All. Toggles at the bottom right of the toolbar.</li><li><strong>Clear Filters</strong> — resets all filters.</li><li><strong>Refresh</strong> — manual refresh (the page also auto-polls running jobs every 10 seconds).</li><li><strong>New Job</strong> button (top right).</li></ul><p>A live counter shows how many jobs are currently running.</p><h3 id="columns" tabindex="-1">Columns <a class="header-anchor" href="#columns" aria-label="Permalink to &quot;Columns&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Column</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Job</strong></td><td>Job type label (Tenant Clone, etc.), the job number (<code>#123</code>), a dry-run flag, and the attempt count if retried.</td></tr><tr><td><strong>Subject</strong></td><td>Compact description — &quot;Old Tenant (ABC) on prod-1&quot; or &quot;prod-1 → staging-1&quot; for an instance replace.</td></tr><tr><td><strong>Status</strong></td><td>Queued / Running / Succeeded / Failed.</td></tr><tr><td><strong>Summary</strong></td><td>Per-tenant progress for instance replaces (&quot;3 / 27 tenants&quot;); the created tenant code for clones; a generic summary otherwise.</td></tr><tr><td><strong>Started</strong></td><td>Relative timestamp.</td></tr><tr><td><strong>Duration</strong></td><td>Elapsed time in human-readable form (&quot;2h 15m&quot;).</td></tr><tr><td><strong>By</strong></td><td>Avatar of the user who requested the job.</td></tr></tbody></table><p>Click a row to open the right-hand drawer with the job&#39;s logs, outcomes, and actions.</p><h3 id="job-lineage" tabindex="-1">Job lineage <a class="header-anchor" href="#job-lineage" aria-label="Permalink to &quot;Job lineage&quot;">​</a></h3><p>Retries of the same job are grouped as one row — you see the latest attempt&#39;s state and the attempt count, not separate rows per retry.</p><h2 id="creating-a-new-job" tabindex="-1">Creating a new job <a class="header-anchor" href="#creating-a-new-job" aria-label="Permalink to &quot;Creating a new job&quot;">​</a></h2><p>Click <strong>New Job</strong>. The wizard has two steps.</p><h3 id="step-1-—-choose-the-job-type" tabindex="-1">Step 1 — Choose the job type <a class="header-anchor" href="#step-1-—-choose-the-job-type" aria-label="Permalink to &quot;Step 1 — Choose the job type&quot;">​</a></h3><p>A grid of five cards. Click one.</p><h3 id="step-2-—-configure" tabindex="-1">Step 2 — Configure <a class="header-anchor" href="#step-2-—-configure" aria-label="Permalink to &quot;Step 2 — Configure&quot;">​</a></h3><p>Fields depend on the type:</p><ul><li><strong>Tenant Clone</strong> / <strong>Tenant Import</strong> — source/target tenant, target instance, <strong>user-email remap</strong> section (explicit mappings if you want to anonymise PII), dry-run toggle.</li><li><strong>Tenant Delete</strong> — source tenant, dry-run toggle.</li><li><strong>Tenant Export</strong> — source tenant, dry-run toggle.</li><li><strong>Instance Replace</strong> — source instance, target instance, dry-run toggle.</li></ul><p>Live (non-dry-run) destructive operations show red borders and require explicit confirmation. <strong>Dry-run is the default.</strong></p><p>Click <strong>Run</strong>. The job appears in the list with status <code>queued</code> then <code>running</code>.</p><h2 id="job-drawer" tabindex="-1">Job drawer <a class="header-anchor" href="#job-drawer" aria-label="Permalink to &quot;Job drawer&quot;">​</a></h2><p>Click any row to slide out the drawer. Sections:</p><ul><li><strong>Header</strong> — job type, status, dry-run flag, attempt count, started time, duration.</li><li><strong>Subject</strong> — what is being acted on (tenant, instance, or both).</li><li><strong>Phase logs</strong> — collapsible groups (preflight, clone, import, etc.). Phases with errors or warnings auto-open.</li><li><strong>Live progress</strong> — for in-flight jobs, the current phase and percentage.</li><li><strong>Outcomes</strong> — what changed, broken down by category.</li><li><strong>Actions</strong> — context-dependent: <ul><li><strong>Rerun</strong> / <strong>Retry</strong> / <strong>Resume</strong> — the label depends on job type and current status. For instance replaces this resumes only the failed tenants.</li><li><strong>Rollback</strong> — visible if the job is part of a failed instance-replace sequence; cleans up orphaned tenants.</li><li><strong>Download artifact</strong> / <strong>Upload artifact</strong> — for exports and imports respectively.</li></ul></li></ul><h3 id="instance-replace-progress" tabindex="-1">Instance-replace progress <a class="header-anchor" href="#instance-replace-progress" aria-label="Permalink to &quot;Instance-replace progress&quot;">​</a></h3><p>Instance-replace jobs include a per-tenant progress table in the drawer with source code, target code, and per-tenant status. You can see exactly which tenants succeeded and which failed mid-replace.</p><h2 id="best-practice" tabindex="-1">Best practice <a class="header-anchor" href="#best-practice" aria-label="Permalink to &quot;Best practice&quot;">​</a></h2><ol><li><strong>Always dry-run first.</strong> A failing dry run tells you what would have gone wrong without doing damage.</li><li><strong>Validate the artifact for exports</strong> before relying on it for an import. Download and inspect.</li><li><strong>For instance replaces</strong>, schedule a window — even with parallelism the wall-clock time scales with tenant count.</li><li><strong>Watch the drawer&#39;s phase log</strong> during the first few minutes of a live run. Most failures surface early (preflight, capacity, permissions).</li></ol>',31)])])}const p=e(o,[["render",s]]);export{u as __pageData,p as default};
